export default function Navbar({ setPage, user, onLogout }) {
  return (
    <nav className="top-nav">
      <button className="top-nav-logo" onClick={() => setPage("home")}>
        <div className="top-nav-logo-icon">🍽</div>
        RecipeNest
      </button>
      <div className="top-nav-links">
        <button className="top-nav-link" onClick={() => setPage("home")}>Discover</button>
        <button className="top-nav-link">Categories</button>
        <button className="top-nav-link">Chefs</button>
      </div>
      <div className="top-nav-actions">
        <button className="top-nav-icon">🔍</button>
        {user ? (
          <>
            <span className="top-nav-user">Welcome, {user.name}!</span>
            <button className="top-nav-link" onClick={() => {
              if (user.role === "user") setPage("user-dashboard");
              else if (user.role === "chef") setPage("chef-dashboard");
              else if (user.role === "admin") setPage("admin-dashboard");
            }}>
              Dashboard
            </button>
            <button className="top-nav-link" onClick={onLogout}>Logout</button>
          </>
        ) : (
          <>
            <button className="top-nav-link" onClick={() => setPage("login")}>Sign In</button>
            <button className="top-nav-cta" onClick={() => setPage("signup")}>Get Started</button>
          </>
        )}
      </div>
    </nav>
  );
}
